"use client";

import React, { useMemo, useState, useCallback } from "react";
import { motion } from "framer-motion";
import {
  CheckCircle2,
  Clock,
  AlertTriangle,
  ListTodo,
  TrendingUp,
  Flame,
  FolderOpen,
  ArrowRight,
  PartyPopper,
  ChevronLeft,
  ChevronRight,
  Plus,
  Users,
  Mail,
} from "lucide-react";
import { useApp } from "@/store/AppContext";
import { formatRelativeDate, getPriorityColor } from "@/lib/nlp";
import QuotesCarousel from "./QuotesCarousel";
import PomodoroWidget from "./PomodoroWidget";
import WorkspaceModal from "./WorkspaceModal";

const PAGE_SIZE = 10;
const PRIORITY_LABELS = ["Urgent", "High", "Medium", "Low"] as const;

function toDateKey(date: Date): string {
  return date.toISOString().split("T")[0];
}

export default function DashboardView() {
  const {
    state,
    dispatch,
    openTaskModal,
    switchWorkspace,
    acceptInvitationAction,
    declineInvitationAction,
  } = useApp();
  const [rcPage, setRcPage] = useState(0);
  const [foldersPage, setFoldersPage] = useState(0);
  const [createWsOpen, setCreateWsOpen] = useState(false);
  const isDoneTask = useCallback(
    (t: (typeof state.tasks)[number]) => t.completed || t.status === "done",
    [],
  );

  const stats = useMemo(() => {
    const now = new Date();
    const todayKey = toDateKey(now);
    const total = state.tasks.length;
    const completed = state.tasks.filter((t) => isDoneTask(t)).length;
    const completedToday = state.tasks.filter((t) =>
      t.completedAt?.startsWith(todayKey),
    ).length;
    const pending = state.tasks.filter((t) => !isDoneTask(t)).length;
    const overdue = state.tasks.filter((t) => {
      if (isDoneTask(t) || !t.dueDate) return false;
      return new Date(t.dueDate) < new Date(todayKey);
    }).length;
    const highPriority = state.tasks.filter(
      (t) => !t.completed && t.priority <= 2,
    ).length;

    // Streak
    let streak = 0;
    for (let i = 0; i < 365; i++) {
      const d = new Date(now);
      d.setDate(d.getDate() - i);
      const key = toDateKey(d);
      const count = state.tasks.filter((t) =>
        t.completedAt?.startsWith(key),
      ).length;
      if (count > 0) streak++;
      else if (i > 0) break;
    }

    return {
      total,
      completed,
      completedToday,
      pending,
      overdue,
      highPriority,
      streak,
    };
  }, [state.tasks, isDoneTask]);

  const upcomingTasks = useMemo(() => {
    return state.tasks
      .filter((t) => !isDoneTask(t) && t.dueDate)
      .sort(
        (a, b) =>
          new Date(a.dueDate!).getTime() - new Date(b.dueDate!).getTime(),
      )
      .slice(0, 5);
  }, [state.tasks, isDoneTask]);

  const recentCompleted = useMemo(() => {
    return state.tasks
      .filter((t) => isDoneTask(t) && (t.completedAt || t.updatedAt))
      .sort(
        (a, b) =>
          new Date(b.completedAt || b.updatedAt).getTime() -
          new Date(a.completedAt || a.updatedAt).getTime(),
      );
  }, [state.tasks, isDoneTask]);

  const folderStats = useMemo(() => {
    return state.folders.map((f) => ({
      ...f,
      total: state.tasks.filter((t) => t.folderId === f.id).length,
      pending: state.tasks.filter((t) => t.folderId === f.id && !isDoneTask(t))
        .length,
    }));
  }, [state.tasks, state.folders, isDoneTask]);

  const completionRate =
    stats.total > 0 ? Math.round((stats.completed / stats.total) * 100) : 0;

  const statCards = [
    {
      label: "Total Tasks",
      value: stats.total,
      icon: ListTodo,
      color: "var(--color-accent)",
    },
    {
      label: "Completed Today",
      value: stats.completedToday,
      icon: CheckCircle2,
      color: "var(--color-success)",
    },
    {
      label: "Overdue",
      value: stats.overdue,
      icon: AlertTriangle,
      color: "var(--color-danger)",
    },
    {
      label: "Streak",
      value: `${stats.streak}d`,
      icon: Flame,
      color: "var(--color-warning)",
    },
  ];

  const container = {
    hidden: { opacity: 0 },
    show: { opacity: 1, transition: { staggerChildren: 0.05 } },
  };
  const item = { hidden: { opacity: 0, y: 12 }, show: { opacity: 1, y: 0 } };

  return (
    <motion.div
      variants={container}
      initial="hidden"
      animate="show"
      className="space-y-6 max-w-5xl mx-auto"
    >
      {/* Greeting + Quotes */}
      <motion.div variants={item}>
        <h1
          className="text-2xl font-bold mb-1"
          style={{ color: "var(--color-text-primary)" }}
        >
          {getGreeting()}
        </h1>
        <p
          className="text-sm mb-4"
          style={{ color: "var(--color-text-tertiary)" }}
        >
          You have{" "}
          <strong style={{ color: "var(--color-text-primary)" }}>
            {stats.pending}
          </strong>{" "}
          task{stats.pending !== 1 ? "s" : ""} remaining today
        </p>
        <QuotesCarousel />
      </motion.div>

      {/* Stat cards */}
      <motion.div
        variants={item}
        className="grid grid-cols-2 lg:grid-cols-4 gap-3"
      >
        {statCards.map((s) => (
          <div
            key={s.label}
            className="rounded-2xl p-4 flex items-center gap-3"
            style={{
              background: "var(--color-surface)",
              border: "1px solid var(--color-border)",
            }}
          >
            <div
              className="w-10 h-10 rounded-xl flex items-center justify-center"
              style={{ background: `${s.color}15` }}
            >
              <s.icon size={18} style={{ color: s.color }} />
            </div>
            <div>
              <div
                className="text-xl font-bold"
                style={{ color: "var(--color-text-primary)" }}
              >
                {s.value}
              </div>
              <div
                className="text-[11px]"
                style={{ color: "var(--color-text-tertiary)" }}
              >
                {s.label}
              </div>
            </div>
          </div>
        ))}
      </motion.div>

      {/* Progress bar */}
      <motion.div
        variants={item}
        className="rounded-2xl p-4"
        style={{
          background: "var(--color-surface)",
          border: "1px solid var(--color-border)",
        }}
      >
        <div className="flex items-center justify-between mb-2">
          <span
            className="text-sm font-medium"
            style={{ color: "var(--color-text-primary)" }}
          >
            Overall Progress
          </span>
          <span
            className="text-sm font-bold"
            style={{ color: "var(--color-accent)" }}
          >
            {completionRate}%
          </span>
        </div>
        <div
          className="w-full h-2.5 rounded-full overflow-hidden"
          style={{ background: "var(--color-border)" }}
        >
          <motion.div
            className="h-full rounded-full"
            style={{ background: "linear-gradient(90deg, #6366f1, #8b5cf6)" }}
            initial={{ width: 0 }}
            animate={{ width: `${completionRate}%` }}
            transition={{ duration: 0.8, ease: "easeOut" }}
          />
        </div>
        <div
          className="flex justify-between mt-1.5 text-[11px]"
          style={{ color: "var(--color-text-tertiary)" }}
        >
          <span>{stats.completed} completed</span>
          <span>{stats.pending} remaining</span>
        </div>
      </motion.div>

      {/* Two column layout: Upcoming + Pomodoro */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        {/* Upcoming tasks */}
        <motion.div
          variants={item}
          className="lg:col-span-2 rounded-2xl p-4"
          style={{
            background: "var(--color-surface)",
            border: "1px solid var(--color-border)",
          }}
        >
          <div className="flex items-center justify-between mb-3">
            <h2
              className="text-sm font-semibold"
              style={{ color: "var(--color-text-primary)" }}
            >
              <Clock size={14} className="inline mr-1.5 -mt-0.5" />
              Upcoming Tasks
            </h2>
            <button
              onClick={() =>
                dispatch({ type: "SET_VIEW_MODE", payload: "list" })
              }
              className="text-xs flex items-center gap-1 hover:opacity-70 transition-opacity"
              style={{ color: "var(--color-accent)" }}
            >
              View all <ArrowRight size={12} />
            </button>
          </div>
          {upcomingTasks.length === 0 ?
            <p
              className="text-sm py-6 text-center"
              style={{ color: "var(--color-text-tertiary)" }}
            >
              No upcoming tasks — great job!{" "}
              <PartyPopper size={14} className="inline-block ml-1" />
            </p>
          : <div className="space-y-2">
              {upcomingTasks.map((task) => (
                <button
                  key={task.id}
                  onClick={() => openTaskModal({ mode: "edit", task })}
                  className="w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-left transition-colors hover:opacity-80"
                  style={{ background: "var(--color-background)" }}
                >
                  <div
                    className="w-2 h-2 rounded-full shrink-0"
                    style={{ background: getPriorityColor(task.priority) }}
                  />
                  <span
                    className="flex-1 text-sm truncate"
                    style={{ color: "var(--color-text-primary)" }}
                  >
                    {task.title}
                  </span>
                  {task.dueDate && (
                    <span
                      className="text-[11px] shrink-0"
                      style={{ color: "var(--color-text-tertiary)" }}
                    >
                      {formatRelativeDate(task.dueDate)}
                    </span>
                  )}
                </button>
              ))}
            </div>
          }
        </motion.div>

        {/* Pomodoro */}
        <motion.div variants={item}>
          <PomodoroWidget />
        </motion.div>
      </div>

      {/* Two column: Recently completed + Folders */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        {/* Recently completed */}
        <motion.div
          variants={item}
          className="rounded-2xl p-4"
          style={{
            background: "var(--color-surface)",
            border: "1px solid var(--color-border)",
          }}
        >
          <h2
            className="text-sm font-semibold mb-3"
            style={{ color: "var(--color-text-primary)" }}
          >
            <CheckCircle2 size={14} className="inline mr-1.5 -mt-0.5" />
            Recently Completed
          </h2>
          {recentCompleted.length === 0 ?
            <p
              className="text-sm py-4 text-center"
              style={{ color: "var(--color-text-tertiary)" }}
            >
              No completed tasks yet
            </p>
          : (() => {
              const rcTotalPages = Math.ceil(
                recentCompleted.length / PAGE_SIZE,
              );
              const rcSlice = recentCompleted.slice(
                rcPage * PAGE_SIZE,
                rcPage * PAGE_SIZE + PAGE_SIZE,
              );
              return (
                <>
                  <div
                    className="overflow-y-auto space-y-2"
                    style={{ maxHeight: "calc(5 * 44px)" }}
                  >
                    {rcSlice.map((task) => (
                      <div
                        key={task.id}
                        className="flex items-center gap-3 px-3 py-2 rounded-xl"
                        style={{ background: "var(--color-background)" }}
                      >
                        <CheckCircle2
                          size={14}
                          style={{ color: "var(--color-success)" }}
                        />
                        <span
                          className="flex-1 text-sm truncate line-through opacity-60"
                          style={{ color: "var(--color-text-primary)" }}
                        >
                          {task.title}
                        </span>
                        {task.completedAt && (
                          <span
                            className="text-[11px] shrink-0"
                            style={{ color: "var(--color-text-tertiary)" }}
                          >
                            {formatRelativeDate(task.completedAt.split("T")[0])}
                          </span>
                        )}
                      </div>
                    ))}
                  </div>
                  {rcTotalPages > 1 && (
                    <div
                      className="flex items-center justify-between mt-3 pt-2"
                      style={{ borderTop: "1px solid var(--color-border)" }}
                    >
                      <button
                        onClick={() => setRcPage((p) => Math.max(0, p - 1))}
                        disabled={rcPage === 0}
                        className="p-1 rounded-lg transition-colors disabled:opacity-30"
                        style={{ color: "var(--color-text-secondary)" }}
                      >
                        <ChevronLeft size={14} />
                      </button>
                      <span
                        className="text-[11px]"
                        style={{ color: "var(--color-text-tertiary)" }}
                      >
                        {rcPage + 1} / {rcTotalPages}
                      </span>
                      <button
                        onClick={() =>
                          setRcPage((p) => Math.min(rcTotalPages - 1, p + 1))
                        }
                        disabled={rcPage === rcTotalPages - 1}
                        className="p-1 rounded-lg transition-colors disabled:opacity-30"
                        style={{ color: "var(--color-text-secondary)" }}
                      >
                        <ChevronRight size={14} />
                      </button>
                    </div>
                  )}
                </>
              );
            })()
          }
        </motion.div>

        {/* Folders overview */}
        <motion.div
          variants={item}
          className="rounded-2xl p-4"
          style={{
            background: "var(--color-surface)",
            border: "1px solid var(--color-border)",
          }}
        >
          <h2
            className="text-sm font-semibold mb-3"
            style={{ color: "var(--color-text-primary)" }}
          >
            <FolderOpen size={14} className="inline mr-1.5 -mt-0.5" />
            Folders
          </h2>
          {(() => {
            const fTotalPages = Math.ceil(folderStats.length / PAGE_SIZE);
            const fSlice = folderStats.slice(
              foldersPage * PAGE_SIZE,
              foldersPage * PAGE_SIZE + PAGE_SIZE,
            );
            return (
              <>
                <div
                  className="overflow-y-auto space-y-2"
                  style={{ maxHeight: "calc(5 * 48px)" }}
                >
                  {fSlice.map((folder) => (
                    <button
                      key={folder.id}
                      onClick={() => {
                        dispatch({
                          type: "SET_ACTIVE_FOLDER",
                          payload: folder.id,
                        });
                        dispatch({ type: "SET_VIEW_MODE", payload: "list" });
                      }}
                      className="w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-left transition-colors hover:opacity-80"
                      style={{ background: "var(--color-background)" }}
                    >
                      <div
                        className="w-2.5 h-2.5 rounded-full shrink-0"
                        style={{ background: folder.color || "#6366f1" }}
                      />
                      <span
                        className="flex-1 text-sm"
                        style={{ color: "var(--color-text-primary)" }}
                      >
                        {folder.name}
                      </span>
                      <span
                        className="text-[11px]"
                        style={{ color: "var(--color-text-tertiary)" }}
                      >
                        {folder.pending} pending
                      </span>
                      <div
                        className="w-12 h-1.5 rounded-full overflow-hidden"
                        style={{ background: "var(--color-border)" }}
                      >
                        <div
                          className="h-full rounded-full"
                          style={{
                            background: folder.color || "#6366f1",
                            width:
                              folder.total > 0 ?
                                `${((folder.total - folder.pending) / folder.total) * 100}%`
                              : "0%",
                          }}
                        />
                      </div>
                    </button>
                  ))}
                </div>
                {fTotalPages > 1 && (
                  <div
                    className="flex items-center justify-between mt-3 pt-2"
                    style={{ borderTop: "1px solid var(--color-border)" }}
                  >
                    <button
                      onClick={() => setFoldersPage((p) => Math.max(0, p - 1))}
                      disabled={foldersPage === 0}
                      className="p-1 rounded-lg transition-colors disabled:opacity-30"
                      style={{ color: "var(--color-text-secondary)" }}
                    >
                      <ChevronLeft size={14} />
                    </button>
                    <span
                      className="text-[11px]"
                      style={{ color: "var(--color-text-tertiary)" }}
                    >
                      {foldersPage + 1} / {fTotalPages}
                    </span>
                    <button
                      onClick={() =>
                        setFoldersPage((p) => Math.min(fTotalPages - 1, p + 1))
                      }
                      disabled={foldersPage === fTotalPages - 1}
                      className="p-1 rounded-lg transition-colors disabled:opacity-30"
                      style={{ color: "var(--color-text-secondary)" }}
                    >
                      <ChevronRight size={14} />
                    </button>
                  </div>
                )}
              </>
            );
          })()}
        </motion.div>
      </div>

      {/* Priority distribution */}
      <motion.div
        variants={item}
        className="rounded-2xl p-4"
        style={{
          background: "var(--color-surface)",
          border: "1px solid var(--color-border)",
        }}
      >
        <h2
          className="text-sm font-semibold mb-3"
          style={{ color: "var(--color-text-primary)" }}
        >
          <TrendingUp size={14} className="inline mr-1.5 -mt-0.5" />
          Priority Distribution
        </h2>
        <div className="grid grid-cols-4 gap-3">
          {([1, 2, 3, 4] as const).map((p) => {
            const count = state.tasks.filter(
              (t) => !t.completed && t.priority === p,
            ).length;
            return (
              <div key={p} className="text-center">
                <div
                  className="text-lg font-bold"
                  style={{ color: getPriorityColor(p) }}
                >
                  {count}
                </div>
                <div
                  className="text-[11px]"
                  style={{ color: "var(--color-text-tertiary)" }}
                >
                  {PRIORITY_LABELS[p - 1]}
                </div>
              </div>
            );
          })}
        </div>
      </motion.div>

      {/* Workspaces */}
      {state.user && (
        <motion.div
          variants={item}
          className="rounded-2xl p-4"
          style={{
            background: "var(--color-surface)",
            border: "1px solid var(--color-border)",
          }}
        >
          <div className="flex items-center justify-between mb-3">
            <h2
              className="text-sm font-semibold"
              style={{ color: "var(--color-text-primary)" }}
            >
              <Users size={14} className="inline mr-1.5 -mt-0.5" />
              Workspaces
            </h2>
            <button
              onClick={() => setCreateWsOpen(true)}
              className="text-xs flex items-center gap-1 hover:opacity-70 transition-opacity"
              style={{ color: "var(--color-accent)" }}
            >
              <Plus size={12} /> New
            </button>
          </div>

          {(
            state.workspaces.length === 0 &&
            state.pendingInvitations.length === 0
          ) ?
            <div className="py-6 text-center">
              <div
                className="w-12 h-12 rounded-2xl mx-auto mb-3 flex items-center justify-center"
                style={{ background: "var(--color-accent-light)" }}
              >
                <Users size={20} style={{ color: "var(--color-accent)" }} />
              </div>
              <p
                className="text-sm font-medium mb-1"
                style={{ color: "var(--color-text-primary)" }}
              >
                Collaborate with others
              </p>
              <p
                className="text-xs mb-3"
                style={{ color: "var(--color-text-tertiary)" }}
              >
                Create a workspace to share tasks and work together
              </p>
              <button
                onClick={() => setCreateWsOpen(true)}
                className="px-4 py-2 rounded-xl text-xs font-semibold text-white transition-all hover:opacity-90"
                style={{
                  background: "linear-gradient(135deg, #6366f1, #8b5cf6)",
                }}
              >
                <Plus size={12} className="inline mr-1 -mt-0.5" />
                Create workspace
              </button>
            </div>
          : <div className="space-y-2">
              {/* Workspace list */}
              {state.workspaces.map((ws) => (
                <button
                  key={ws.workspaceId}
                  onClick={() => switchWorkspace(ws.workspaceId)}
                  className="w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-left transition-colors hover:opacity-80"
                  style={{ background: "var(--color-background)" }}
                >
                  <span className="text-lg leading-none">{ws.emoji}</span>
                  <div className="flex-1 min-w-0">
                    <p
                      className="text-sm font-medium truncate"
                      style={{ color: "var(--color-text-primary)" }}
                    >
                      {ws.name}
                    </p>
                    <div
                      className="flex items-center gap-1 mt-0.5"
                      style={{ color: "var(--color-text-tertiary)" }}
                    >
                      <Users size={10} />
                      <span className="text-[11px]">
                        {ws.memberCount} member{ws.memberCount !== 1 ? "s" : ""}
                      </span>
                    </div>
                  </div>
                  <ArrowRight
                    size={14}
                    style={{ color: "var(--color-text-tertiary)" }}
                  />
                </button>
              ))}

              {/* Pending invitations */}
              {state.pendingInvitations.length > 0 && (
                <>
                  <p
                    className="text-[10px] font-semibold uppercase tracking-wider pt-2 flex items-center gap-1.5"
                    style={{ color: "var(--color-text-tertiary)" }}
                  >
                    <Mail size={10} />
                    Invitations ({state.pendingInvitations.length})
                  </p>
                  {state.pendingInvitations.map((inv) => (
                    <div
                      key={inv.id}
                      className="flex items-center gap-3 px-3 py-2.5 rounded-xl"
                      style={{ background: "var(--color-background)" }}
                    >
                      <span className="text-lg leading-none">
                        {inv.workspaceEmoji}
                      </span>
                      <div className="flex-1 min-w-0">
                        <p
                          className="text-sm font-medium truncate"
                          style={{ color: "var(--color-text-primary)" }}
                        >
                          {inv.workspaceName}
                        </p>
                        <p
                          className="text-[11px] truncate"
                          style={{ color: "var(--color-text-tertiary)" }}
                        >
                          from {inv.invitedByName} &middot; {inv.role}
                        </p>
                      </div>
                      <div className="flex gap-1.5">
                        <button
                          onClick={() => acceptInvitationAction(inv)}
                          className="px-2.5 py-1 rounded-lg text-[10px] font-medium text-white"
                          style={{ background: "var(--color-accent)" }}
                        >
                          Accept
                        </button>
                        <button
                          onClick={() => declineInvitationAction(inv.id)}
                          className="px-2.5 py-1 rounded-lg text-[10px] font-medium"
                          style={{
                            color: "var(--color-text-tertiary)",
                            background: "var(--color-surface)",
                            border: "1px solid var(--color-border)",
                          }}
                        >
                          Decline
                        </button>
                      </div>
                    </div>
                  ))}
                </>
              )}
            </div>
          }
        </motion.div>
      )}

      <WorkspaceModal
        open={createWsOpen}
        onClose={() => setCreateWsOpen(false)}
      />
    </motion.div>
  );
}

function getGreeting(): string {
  const h = new Date().getHours();
  if (h < 12) return "Good morning";
  if (h < 17) return "Good afternoon";
  return "Good evening";
}
